#!/usr/bin/env python3
import argparse
import subprocess
import shlex

def run_docker_cleanup():
    """Wrapper for `docker system prune -a --volumes` with safety checks."""
    print("⚠️  WARNING: This will remove ALL unused Docker containers, networks, images, and volumes.")
    confirm = input("Type 'yes' to proceed: ")
    if confirm.lower() == 'yes':
        try:
            subprocess.run(
                shlex.split("docker system prune -a --volumes"),
                check=True,
                capture_output=True,
            )
            print("✅ Docker cleanup completed successfully.")
        except subprocess.CalledProcessError as e:
            print(f"❌ Error during cleanup: {e.stderr.decode()}")
    else:
        print("Operation cancelled.")

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Simplified Docker cleanup tool")
    parser.add_argument("--force", action="store_true", help="Skip confirmation prompt")
    args = parser.parse_args()
    if args.force or input("Proceed with cleanup? (y/N): ").lower() == 'y':
        run_docker_cleanup()
